use std::fs::File;
use std::io::{Result, Write};
use std::path::PathBuf;

fn main() -> Result<()> {
    gen_vector_asm()?;
    gen_vectors_rs()?;
    Ok(())
}

/// Generate assembly file for x86_64 trap vector stubs.
fn gen_vector_asm() -> Result<()> {
    let out_path = PathBuf::from(std::env::var("OUT_DIR").unwrap());
    let mut f = File::create(out_path.join("vector.S"))?;

    writeln!(f, "# generated by build.rs - do not edit")?;
    writeln!(f, ".section .text")?;
    for i in 0..256 {
        writeln!(f, ".global vector{}", i)?;
        writeln!(f, "vector{}:", i)?;
        if !(i == 8 || (10..=14).contains(&i) || i == 17) {
            writeln!(f, "\tpush 0")?;
        }
        writeln!(f, "\tpush {}", i)?;
        writeln!(f, "\tjmp __alltraps")?;
    }
    Ok(())
}

/// Rust table of trap vector entry points (avoids .rodata R_X86_64_64 relocations in static kernels).
fn gen_vectors_rs() -> Result<()> {
    let out_path = PathBuf::from(std::env::var("OUT_DIR").unwrap());
    let mut f = File::create(out_path.join("vectors.rs"))?;

    writeln!(f, "// generated by build.rs - do not edit")?;
    for i in 0..256 {
        writeln!(f, "extern \"C\" {{ fn vector{}(); }}", i)?;
    }
    writeln!(f, "pub static VECTORS: [unsafe extern \"C\" fn(); 256] = [")?;
    for i in 0..256 {
        writeln!(f, "    vector{},", i)?;
    }
    writeln!(f, "];")?;
    Ok(())
}
